1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	interface Policy {
32	  items: Item[];
33	  remainingCap: number;
34	}
35	
36	type QuoteResult = { premium: number };
37	type ClaimResult = { payout: number; remainingCap: number };
38	type StepResult = QuoteResult | ClaimResult;
39	
40	const BASE_PREMIUM: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: 25,
46	};
47	
48	const INSURANCE_VALUE: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	  rune: 250,
54	  moonstone: 250,
55	};
56	
57	const DEDUCTIBLE = 100;
58	const CAP_MULTIPLIER = 2;
59	const HIGH_DAMAGE_ENCH_THRESHOLD = 8;
60	const HIGH_DAMAGE_REIMBURSE_RATE = 0.5;
61	
62	const FIRST_INSURANCE_RATE = 0.1;
63	const CURSE_RATE = 0.5;
64	const HIGH_ENCH_RATE = 0.3;
65	const HIGH_ENCH_THRESHOLD = 5;
66	const LOYALTY_RATE = 0.2;
67	const LOYALTY_THRESHOLD = 2;
68	const FOLLOWUP_RATE = 0.15;
69	const PROCESSING_FEE = 5;
70	
71	const COMPONENT_PREMIUM = 25;
72	const BLOCK_SIZE = 3;
73	const BLOCK_PREMIUM = 60;
74	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
75	
76	const componentBasePremium = (count: number): number =>
77	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
78	
79	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
80	
81	const isMainItem = (item: Item): boolean => !isComponent(item);
82	
83	const countByType = (items: Item[]): Map<string, number> =>
84	  items.reduce(
85	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
86	    new Map<string, number>(),
87	  );
88	
89	const componentTotal = (items: Item[]): number =>
90	  [...countByType(items.filter(isComponent)).values()].reduce(
91	    (sum, count) => sum + componentBasePremium(count),
92	    0,
93	  );
94	
95	const basePremium = (items: Item[]): number => {
96	  const mainTotal = items
97	    .filter(isMainItem)
98	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
99	  return mainTotal + componentTotal(items);
100	};
101	
102	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
103	
104	const surchargeFor = (
105	  items: Item[],
106	  qualifies: (item: Item) => boolean,
107	  rate: number,
108	): number =>
109	  items
110	    .filter((item) => isMainItem(item) && qualifies(item))
111	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
112	
113	const isCursed = (item: Item): boolean => item.cursed === true;
114	
115	const curseSurcharge = (items: Item[]): number =>
116	  surchargeFor(items, isCursed, CURSE_RATE);
117	
118	const isHighlyEnchanted = (item: Item): boolean =>
119	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
120	
121	const highEnchantmentSurcharge = (items: Item[]): number =>
122	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
123	
124	const discountWhen = (policyBase: number, qualifies: boolean, rate: number): number =>
125	  qualifies ? policyBase * rate : 0;
126	
127	const isLoyal = (years: number): boolean => years >= LOYALTY_THRESHOLD;
128	
129	const quotePremium = (items: Item[], years: number, isFollowUp: boolean): number => {
130	  const policyBase = basePremium(items);
131	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
132	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
133	  const loyalty = discountWhen(policyBase, isLoyal(years), LOYALTY_RATE);
134	  const followUp = discountWhen(policyBase, isFollowUp, FOLLOWUP_RATE);
135	  return Math.ceil(
136	    policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE,
137	  );
138	};
139	
140	const insuranceSum = (items: Item[]): number =>
141	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
142	
143	const reimbursableAmount = (amount: number, item: Item | undefined): number => {
144	  if ((item?.enchantment ?? 0) >= HIGH_DAMAGE_ENCH_THRESHOLD) {
145	    return amount * HIGH_DAMAGE_REIMBURSE_RATE;
146	  }
147	  return amount;
148	};
149	
150	const damagePayout = (damage: Damage, item: Item | undefined): number =>
151	  Math.max(reimbursableAmount(damage.amount, item) - DEDUCTIBLE, 0);
152	
153	const openPolicy = (items: Item[]): Policy => ({
154	  items,
155	  remainingCap: insuranceSum(items) * CAP_MULTIPLIER,
156	});
157	
158	const insuredItem = (policy: Policy, itemType: string): Item | undefined =>
159	  policy.items.find((item) => item.type === itemType);
160	
161	const processClaim = (policy: Policy, claim: ClaimStep): ClaimResult => {
162	  const payout = claim.incident.damages.reduce(
163	    (sum, damage) => sum + damagePayout(damage, insuredItem(policy, damage.itemType)),
164	    0,
165	  );
166	  policy.remainingCap -= payout;
167	  return { payout, remainingCap: policy.remainingCap };
168	};
169	
170	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
171	  const years = scenario.customer.yearsWithMHPCO;
172	  const policies: Policy[] = [];
173	  let quoteCount = 0;
174	  const results = scenario.steps.map((step, index): StepResult => {
175	    if (step.op === "quote") {
176	      const isFollowUp = quoteCount > 0;
177	      quoteCount += 1;
178	      policies[index] = openPolicy(step.items);
179	      return { premium: quotePremium(step.items, years, isFollowUp) };
180	    }
181	    return processClaim(policies[step.policy], step);
182	  });
183	  return { results };
184	};
